const raw = $input.first().json.body.transcricao;

// Remove timestamps e números de linha do SRT
const limpo = raw
  .replace(/^\d+$/gm, '')                          // remove números de linha
  .replace(/\d{2}:\d{2}:\d{2},\d{3} --> \d{2}:\d{2}:\d{2},\d{3}/g, '') // remove timestamps
  .replace(/\n{2,}/g, '\n')                         // remove linhas em branco duplas
  .split('\n')
  .map(l => l.trim())
  .filter(l => l.length > 3)                        // remove linhas muito curtas (ruído)
  .join(' ');

return [{
  json: {
    ambiente:     $input.first().json.body.ambiente,
    turma:        $input.first().json.body.turma,
    linkLoom:     $input.first().json.body.linkLoom,
    linkSlides:   $input.first().json.body.linkSlides,
    transcricao:  limpo,
    data:         new Date().toLocaleDateString('pt-BR'),
  }
}];

const relatorio = $json.output ?? $json.text ?? '';

return [{
  json: {
    relatorio: relatorio.trim()
  }
}];
